function loadGeneContent(){checkAnswers_executed=!1,possible_gene=document.getElementById("gene_dropdown_selection").value,select_Gene()}async function redirectCRISPR(){$("#mainContainer").empty();let e;e=`
		<div class='row'>
			<div class='col-sm-1'></div>
				<div class='col-sm-10' id='content_body'>
					<div id='selection_process'>
					<div id='mode_selection' style='margin-top: 2%;'>
						<p>Please select the dry lab mode you would like to use: </p>
					</div>

					<div id='gene_selection'>
						Please select your gene:
						<div class='btn-group'>
							<select
								class='form-select'
								id='gene_dropdown_selection'
								onchange='possible_gene=(document.getElementById("gene_dropdown_selection").value);'
								aria-label='Select gene for CRISPR analysis'
							>
							</select>
						</div>
					</div>

					<div id='load_button'>
						<button
							type='button'
							class='btn btn-success'
							style='margin-top: 2%;'
							onClick='loadGeneContent()'
						>
							Load Gene
						</button>
					</div>
				</div>

				<div id='work'>
				</div>
			</div>

			<div class='col-sm-1'></div>
		</div>
	`,$("#mainContainer").append(e),await loadCRISPRJSON_Files(),fillGeneList()}
